    	case reflect.Slice, reflect.Array:
    		count := value.Len()
    		validateRet := make(SliceValidationError, 0)
    		for i := range count {
    			if err := v.ValidateStruct(value.Index(i).Interface()); err != nil {
    				validateRet = append(validateRet, err)
    			}
    		}
