72	func getMinVer(v string) (uint64, error) {
73		first := strings.IndexByte(v, '.')
74		last := strings.LastIndexByte(v, '.')
75		if first == last {
76			return strconv.ParseUint(v[first+1:], 10, 64)
77		}
78		return strconv.ParseUint(v[first+1:last], 10, 64)
79	}
